/* VERTAX-01 / RUNT-01 render pipeline and view functions. */

/* ============================================================ *//* RENDER *//* ============================================================ */function render(){ var root = document.getElementById('laiso-root'); if (!root) return; var html = ''; switch (state.view) { case 'home': html = viewHome(); break; case 'add': html = viewAdd(); break; case 'match': html = viewMatch(); break; case 'tracklist': html = viewTracklist(); break; case 'edit-track': html = viewEditTrack(); break; case 'fetching': html = viewFetching(); break; case 'set': html = viewSet(); break; case 'collection': html = viewCollection(); break; case 'discogs-import': html = viewDiscogsImport(); break; case 'backup': html = (typeof window.viewBackup === 'function' ? window.viewBackup() : viewHome()); break; case 'about': html = viewAbout(); break; default: html = viewHome(); } if (state.modal) html += renderModal(); if (state.toast) html += '<div class="laiso-toast">' + esc(state.toast) + '</div>'; if (document.body) document.body.classList.toggle('vertax-dark', state.view === 'live-set'); root.innerHTML = html; if (typeof vertaxAfterRender === 'function') { try { vertaxAfterRender(); } catch(_){} } } function renderAttribution(){ return '<div style="margin-top:24px;padding:12px 0;border-top:1px solid var(--border);text-align:center;font-family:var(--font-mono);font-size:10px;color:var(--text-tertiary);letter-spacing:0.04em;">' + 'BPM/KEY · POWERED BY ' + '<a href="https://www.getsongbpm.com" target="_blank" rel="noopener" style="color:var(--accent-lime-dark);text-decoration:underline;">GetSongBPM</a>' + ' AND ' + '<a href="https://acousticbrainz.org" target="_blank" rel="noopener" style="color:#3a8fd8;text-decoration:underline;">AcousticBrainz</a>' + ' AND ' + '<a href="https://open.spotify.com" target="_blank" rel="noopener" style="color:#1db954;text-decoration:underline;">Spotify</a>' + '</div>'; } /* ---------- DEVICE CHASSIS (top brand strip) ---------- */function renderChassis(rightSlot){ return '' + '<div class="laiso-chassis">' + '<div class="laiso-chassis-row">' + '<div class="laiso-brand-wrap">' + '<div class="laiso-dotmark" aria-hidden="true"><span></span><span></span><span></span></div>' + '<div class="laiso-brand">VERTAX-01<small>by Laiso Buck / Михаил Проскурин</small></div>' + '</div>' + '<div class="laiso-chassis-side">' + (rightSlot || '') + renderThemeToggle() + '</div>' + '</div>' + '</div>'; } function renderCounterLcd(){ var n = (state.collection || []).length; return '<span class="laiso-lcd-mini"><span class="laiso-lcd-mini-dot"></span>' + n + '/1000</span>'; } function renderThemeToggle(){ var theme = (typeof getVertaxTheme === 'function') ? getVertaxTheme() : 'light'; var isDark = theme === 'dark'; return '<button class="vertax-theme-toggle' + (isDark ? ' is-dark' : '') + '" data-action="theme-toggle" aria-label="Переключить тему" title="' + (isDark ? 'Graphite Night' : 'Graphite Ice') + '" type="button"><span class="vertax-theme-toggle-track"><span class="vertax-theme-toggle-icon vertax-theme-icon-ice">ICE</span><span class="vertax-theme-toggle-icon vertax-theme-icon-night">NGT</span><span class="vertax-theme-toggle-handle"></span></span></button>'; } function vertaxPad3(n){ var s = String(n || 0); while (s.length < 3) s = '0' + s; return s; } function renderVertaxDisplay(){ var n = ((state && state.collection) || []).length; var sets = ((state && state.sets) || []).length; return '<div class="vertax-display" id="vertax-display">' + '<div class="vertax-display-top">' + '<span class="vertax-display-status"><span class="vertax-display-led"></span>READY</span>' + '<span class="vertax-display-clock" id="vertax-clock">--<span class="vertax-display-colon">:</span>--</span>' + '</div>' + '<div class="vertax-display-title">DIG. PLAY. SHARE.</div>' + '<div class="vertax-display-stats">' + '<span class="vertax-display-stat"><strong>' + vertaxPad3(n) + '</strong><small>RECORDS</small></span>' + '<span class="vertax-display-stat"><strong>' + vertaxPad3(sets) + '</strong><small>SETS</small></span>' + '<span class="vertax-display-stat"><strong>LOCAL</strong><small>DB</small></span>' + '</div>' + '</div>'; } /* ---------- HOME ---------- */function viewHome(){ return '' + '<div class="laiso-home">' + renderChassis() + renderVertaxDisplay() + '<div class="laiso-mod-label">главное меню</div>' + '<div class="laiso-home-grid">' + '<button class="laiso-btn laiso-btn-main" data-action="go-add">Найти пластинку</button>' + '<button class="laiso-btn laiso-btn-secondary" data-action="go-collection">Коллекция</button>' + '<button class="laiso-btn laiso-btn-secondary" data-action="go-set">Собрать сет</button>' + '<button class="laiso-btn laiso-btn-secondary" data-action="goto-discogs-import">Импорт из Discogs</button>' + '</div>' + '<div class="laiso-home-stickers">' + '<button class="laiso-sticker laiso-sticker-backup" data-action="goto-backup">' + '<span>service</span><strong>Резервная копия</strong><small>сохранить коллекцию</small>' + '</button>' + '<button class="laiso-sticker laiso-sticker-about" data-action="open-about">' + '<span>about</span><strong>О проекте</strong><small>что это за штука</small>' + '</button>' + '<a class="laiso-sticker laiso-sticker-donate" href="https://www.tbank.ru/cf/1ZddEeAvzU1" target="_blank" rel="noopener">' + '<span>support</span><strong>Донат</strong><small>поддержать VERTAX-01</small>' + '</a>' + '</div>' + renderFooter() + '</div>'; } function renderFooter(){ return '' + '<div class="laiso-footer">' + '<div>VERTAX-01 · by Laiso Buck / Михаил Проскурин</div>' + '<div class="laiso-footer-tg"><a href="https://t.me/michael1994lab" target="_blank" rel="noopener">Telegram автору</a></div>' + '<div class="laiso-footer-donate"><a href="https://www.tbank.ru/cf/1ZddEeAvzU1" target="_blank" rel="noopener">Поддержать проект</a></div>' + '</div>'; } function renderHeader(title, opts){ opts = opts || {}; return '' + renderChassis(opts.right || '') + '<div class="laiso-header">' + '<button class="laiso-back" data-action="back">← Назад</button>' + '<h1 class="laiso-h1">' + esc(title) + '</h1>' + '<div style="min-width:54px;"></div>' + '</div>'; } /* ---------- ADD VINYL — Discogs search ---------- */function viewAdd(){ var vinyls = state.vinyls; var canAdd = vinyls.length < SESSION_LIMIT; var hasUsable = vinyls.some(function(v){ return v.status === 'recognized' || v.status === 'manual'; }); var u = state.ui; /* SEARCH MODULE — main and only path on this screen */var searchPanel = '<div class="laiso-mod-label">найти пластинку</div>' + '<div class="laiso-panel">' + '<div class="laiso-search">' + '<input class="laiso-input" type="text" id="search-input" data-bind="searchQuery" data-action="search-input" ' + 'placeholder="Артист, релиз или трек…" autocomplete="off" value="' + esc(u.searchQuery || '') + '">' + '</div>' + '<button class="laiso-btn laiso-btn-block" data-action="discogs-search" style="margin-top:10px;">' + (u.searchLoading ? '<span class="laiso-spinner"></span> Ищу…' : 'Найти в Discogs') + '</button>' + (u.searchError ? '<div class="laiso-hint laiso-hint-warn" style="margin-top:8px;">' + esc(u.searchError) + '</div>' : '<div class="laiso-hint" style="margin-top:8px;">Discogs · виниловые релизы</div>') + renderSearchResults() + '</div>'; /* SESSION LIST MODULE */var listHtml; if (vinyls.length === 0) { listHtml = '<div class="laiso-empty">' + '<strong>Слот пуст</strong>' + 'Введи артиста, релиз или название трека выше' + '</div>'; } else { listHtml = '<div class="laiso-stack-sm">' + vinyls.map(renderVinylCard).join('') + '</div>'; } var limitMsg = !canAdd ? '<div class="laiso-hint laiso-hint-warn" style="text-align:center;margin:8px 0;">' + 'Лимит сессии — ' + SESSION_LIMIT + '. Нажмите «Готово».</div>' : ''; var listSection = '<div class="laiso-mod-label">сессия · ' + vinyls.length + '/' + SESSION_LIMIT + '</div>' + listHtml + limitMsg; return renderHeader('Добавить пластинку') + searchPanel + '<div class="laiso-or">сессия</div>' + listSection + '<div class="laiso-stack" style="margin-top:14px;">' + '<button class="laiso-btn laiso-btn-block" data-action="done-add">Готово → треклисты</button>' + '</div>'; } function viewDiscogsImport(){ var u = state.ui; var loaded = u.discogsImportLoaded && !u.discogsImportLoading; var found = (u.discogsImportVinyls || []).length; if (u.discogsImportEnrichStage) { var stageLabel = u.discogsImportEnrichStage === 'meta' ? 'BPM / Key' : 'треклисты'; var done = u.discogsImportEnrichDone || 0; var total = u.discogsImportEnrichTotal || 0; var pct = total ? Math.round(done * 100 / total) : 0; return renderHeader('Импорт из Discogs') + '<div class="laiso-stack"><div class="laiso-panel"><div class="laiso-mod-label">подгружаю ' + esc(stageLabel) + '</div><div class="laiso-mono-s" style="margin-top:10px;">' + esc(done) + ' / ' + esc(total) + ' (' + esc(pct) + '%)</div><div style="margin-top:10px;height:6px;background:var(--panel-recess);border-radius:999px;overflow:hidden;"><div style="width:' + pct + '%;height:100%;background:var(--accent-lime);transition:width .25s;"></div></div><button class="laiso-btn laiso-btn-secondary laiso-btn-block" data-action="discogs-enrich-cancel" style="margin-top:14px;">Прервать (что успели — уже в коллекции)</button></div></div>'; } var progress = u.discogsImportLoading ? '<div class="laiso-panel"><div class="laiso-mono-s">Загружено: ' + esc(u.discogsImportProgress || 0) + ' пластинок...</div></div>' : ''; var optsBlock = ''; var result = ''; if (loaded) { var tracksChecked = u.discogsImportFetchTracks ? ' checked' : ''; var metaChecked = u.discogsImportFetchMeta ? ' checked' : ''; var metaDisabled = u.discogsImportFetchTracks ? '' : ' disabled'; optsBlock = '<div class="laiso-panel"><div class="laiso-mod-label">опции</div><label class="laiso-check" style="display:flex;gap:10px;align-items:flex-start;margin-top:10px;cursor:pointer;"><input type="checkbox" data-action="toggle-discogs-fetch-tracks"' + tracksChecked + '><span><strong>Сразу подтянуть треклисты</strong><br><span class="laiso-mono-s" style="color:var(--text-secondary);">≈1 сек на пластинку (Discogs API)</span></span></label><label class="laiso-check" style="display:flex;gap:10px;align-items:flex-start;margin-top:10px;cursor:pointer;opacity:' + (metaDisabled?'.45':'1') + ';"><input type="checkbox" data-action="toggle-discogs-fetch-meta"' + metaChecked + metaDisabled + '><span><strong>И BPM / Key</strong><br><span class="laiso-mono-s" style="color:var(--text-secondary);">медленно: ≈0.4 сек на каждый трек</span></span></label></div>'; result = '<div class="laiso-panel"><p style="margin-top:0;">Найдено пластинок: ' + esc(found) + '</p><p>Как добавить в коллекцию?</p><div class="laiso-stack"><button class="laiso-btn laiso-btn-block" data-action="discogs-import-replace">Заменить текущую коллекцию</button><button class="laiso-btn laiso-btn-secondary laiso-btn-block" data-action="discogs-import-merge">Объединить с текущей</button><button class="laiso-btn laiso-btn-secondary laiso-btn-block" data-action="discogs-import-cancel">Отмена</button></div></div>'; } return renderHeader('Импорт из Discogs') + '<div class="laiso-stack"><div class="laiso-panel"><p>Введите ваш Discogs username — и мы загрузим вашу коллекцию автоматически.</p><p>Коллекция должна быть публичной в настройках профиля Discogs.</p></div><div class="laiso-panel"><input class="laiso-input" id="discogs-import-username" data-bind="discogsImportUsername" placeholder="Discogs username" autocomplete="username" value="' + esc(u.discogsImportUsername || '') + '"><button class="laiso-btn laiso-btn-block" data-action="discogs-import-load" style="margin-top:10px;"' + (u.discogsImportLoading ? ' disabled' : '') + '>' + (u.discogsImportLoading ? '<span class="laiso-spinner"></span> Загружаем…' : 'Загрузить коллекцию') + '</button></div>' + progress + optsBlock + result + '</div>'; } function renderSearchResults(){ var u = state.ui; if (u.searchLoading) { return '<div style="text-align:center;padding:20px;"><span class="laiso-spinner"></span> ' + '<span class="laiso-mono-s" style="color:var(--text-secondary);margin-left:8px;">Ищу в Discogs…</span></div>'; } var results = u.searchResults || []; if (results.length === 0) return ''; var top = results[0]; var rest = results.slice(1); var topBlock = '' + '<div class="laiso-mod-label" style="margin-top:14px;">кандидат №1</div>' + '<div class="laiso-match-top">' + (top.thumb ? '<div class="laiso-match-cover" style="margin-bottom:10px;"><img src="' + esc(top.thumb) + '" alt=""></div>' : '') + '<div style="font-weight:600;font-size:14px;text-align:center;margin-bottom:2px;">' + esc(top.title || '—') + '</div>' + '<div class="laiso-meta" style="text-align:center;margin-bottom:10px;text-transform:none;letter-spacing:0;font-size:11px;color:var(--text-secondary);font-family:var(--font-sans);">' + esc((top.label && top.label[0]) || '') + (top.catno ? ' · ' + esc(top.catno) : '') + (top.year ? ' · ' + esc(String(top.year)) : '') + (top.format ? ' · ' + esc((top.format || []).join(' / ')) : '') + '</div>' + '<button class="laiso-btn laiso-btn-block" data-action="search-pick" data-id="' + esc(String(top.id)) + '">Это моя пластинка</button>' + '</div>'; var restBlock = ''; if (rest.length > 0) { restBlock = '<div class="laiso-mod-label" style="margin-top:14px;">варианты</div>' + '<div class="laiso-stack-sm">' + rest.map(function(r){ var meta = ((r.label && r.label[0]) ? esc(r.label[0]) : '') + (r.catno ? ' · ' + esc(r.catno) : '') + (r.year ? ' · ' + esc(String(r.year)) : ''); return '<div class="laiso-search-result" data-action="search-pick" data-id="' + esc(String(r.id)) + '">' + '<div class="laiso-search-result-cover">' + (r.thumb ? '<img src="' + esc(r.thumb) + '" alt="">' : '') + '</div>' + '<div class="laiso-search-result-info">' + '<div class="laiso-search-result-title">' + esc(r.title || '—') + '</div>' + '<div class="laiso-search-result-meta">' + meta + '</div>' + '</div>' + '<div class="laiso-mono-s" style="color:var(--led-lime-dark);">→</div>' + '</div>'; }).join('') + '</div>'; } return topBlock + restBlock; } function renderVinylCard(v){ var coverHtml; if (v.userPhoto) coverHtml = '<img src="' + esc(v.userPhoto) + '" alt="">'; else if (v.coverUrl) coverHtml = '<img src="' + esc(v.coverUrl) + '" alt="">'; else coverHtml = 'нет фото'; var statusMap = { 'awaiting': ['laiso-badge-awaiting','ОЖИДАЕТ'], 'recognized': ['laiso-badge-recognized','НАЙДЕНА'], 'needs_confirmation': ['laiso-badge-confirm','ПОДТВЕРДИТЬ'], 'not_found': ['laiso-badge-not-found','НЕ НАЙДЕНА'], 'manual': ['laiso-badge-manual','ВРУЧНУЮ'] }; var s = statusMap[v.status] || statusMap.awaiting; var spinning = (v.status === 'awaiting' && v._recognizing) ? '<span class="laiso-spinner"></span>' : ''; var canTracklist = (v.status === 'recognized' || v.status === 'manual' || v.status === 'needs_confirmation') && v.tracklist && v.tracklist.length; var canConfirm = v.status === 'needs_confirmation' && state.ui.candidates && state.ui.candidates.length; return '' + '<div class="laiso-vinyl-card laiso-vinyl-card-clickable" data-action="collection-open-vinyl" data-id="' + esc(v.id) + '">' + '<div class="laiso-vinyl-cover">' + coverHtml + '</div>' + '<div class="laiso-vinyl-info">' + '<div class="laiso-vinyl-title">' + esc(v.title || '—') + '</div>' + '<div class="laiso-vinyl-artist">' + esc(v.artist || '—') + '</div>' + '<div class="laiso-vinyl-meta">' + esc(v.label || '') + (v.catno ? ' · ' + esc(v.catno) : '') + (v.year || v.format ? '<br>' + esc(v.year || '') + (v.format ? ' · ' + esc(v.format) : '') : '') + '</div>' + '</div>' + '<div class="laiso-vinyl-actions">' + '<span class="laiso-badge ' + s[0] + '">' + s[1] + ' ' + spinning + '</span>' + '<div class="laiso-menu" data-vinyl-id="' + esc(v.id) + '">' + '<button class="laiso-menu-btn" data-action="toggle-menu" data-id="' + esc(v.id) + '">⋯</button>' + '<div class="laiso-menu-list">' + '<button data-action="collection-open-vinyl" data-id="' + esc(v.id) + '">' + (canTracklist ? 'Открыть треклист' : 'Открыть пластинку') + '</button>' + (v.discogsId ? '<button data-action="load-release-tracklist" data-id="' + esc(v.id) + '">Загрузить треклист</button>' : '') + (canConfirm ? '<button data-action="resume-match" data-id="' + esc(v.id) + '">Подтвердить совпадение…</button>' : '') + '<button data-action="recognize-one" data-id="' + esc(v.id) + '">Распознать заново</button>' + '<button data-action="manual-edit-vinyl" data-id="' + esc(v.id) + '">Править детали…</button>' + '<button data-action="vinyl-toggle-exclude" data-vid="' + esc(v.id) + '">' + (v.excludeFromSets?'Вернуть в сеты':'Пропускать в сетах') + '</button>' + '<button data-action="delete-vinyl" data-id="' + esc(v.id) + '" class="danger">Удалить</button>' + '</div>' + '</div>' + '</div>' + '</div>'; } /* ---------- ADD MODAL ---------- *//* Legacy modal — поиск теперь встроен в Add screen, эта модалка не вызывается из UI, *//* но оставлена пустой на случай старых ссылок. */function renderAddModal(){ return '<div class="laiso-modal-bg" data-action="close-modal-bg">' + '<div class="laiso-modal" data-stop>' + '<h2 class="laiso-modal-title">Поиск перенесён</h2>' + '<p>Поиск пластинок теперь встроен прямо в экран «Добавить пластинку».</p>' + '<button class="laiso-btn laiso-btn-block" data-action="close-modal" style="margin-top:14px;">OK</button>' + '</div>' + '</div>'; } /* ---------- MANUAL VINYL (when not_found / manual edit) ---------- */function renderManualVinylModal(){ var v = state.ui.manualVinyl || {}; return '' + '<div class="laiso-modal-bg" data-action="close-modal-bg">' + '<div class="laiso-modal" data-stop>' + '<div class="laiso-row" style="justify-content:space-between;align-items:center;margin-bottom:8px;">' + '<h2 class="laiso-modal-title">Правка пластинки</h2>' + '<button class="laiso-back" data-action="close-modal">Закрыть</button>' + '</div>' + '<div class="laiso-stack">' + inputField('Артист','mv-artist',v.artist) + inputField('Название','mv-title',v.title) + '<div class="laiso-row">' + '<div class="laiso-grow">' + inputField('Лейбл','mv-label',v.label) + '</div>' + '<div class="laiso-grow">' + inputField('Каталог №','mv-catno',v.catno) + '</div>' + '</div>' + '<div class="laiso-row">' + '<div class="laiso-grow">' + inputField('Год','mv-year',v.year) + '</div>' + '<div class="laiso-grow">' + inputField('Формат','mv-format',v.format) + '</div>' + '</div>' + '<button class="laiso-btn laiso-btn-block" data-action="save-manual-vinyl">Сохранить</button>' + '</div>' + '</div>' + '</div>'; } function inputField(label, id, val){ return '<div><label class="laiso-label">' + esc(label) + '</label>' + '<input class="laiso-input" id="' + esc(id) + '" type="text" value="' + esc(val||'') + '"></div>'; } /* ---------- ABOUT / HELP / CONFIRM CLEAR ---------- */function renderAboutModal(){ return '<div class="laiso-modal-bg" data-action="close-modal-bg"><div class="laiso-modal" data-stop>' + '<div class="laiso-row" style="justify-content:space-between;align-items:center;margin-bottom:8px;">' + '<h2 class="laiso-modal-title">О VERTAX-01</h2><button class="laiso-back" data-action="close-modal">Закрыть</button></div>' + '<div class="laiso-stack">' + '<p>Цифровой DJ-компаньон для винила. Добавь до ' + SESSION_LIMIT + ' пластинок, посмотри треклист, проставь BPM/Key, собери сет по правилу «не два трека с одной пластинки подряд».</p>' + '<p style="font-family:var(--font-mono);font-size:11px;color:var(--text-tertiary);">Discogs · GetSongBPM · AcousticBrainz · IndexedDB</p>' + '<p>by <strong>Laiso Buck / Михаил Проскурин</strong> · <a href="https://t.me/michael1994lab" target="_blank" rel="noopener">t.me/michael1994lab</a></p>' + '<p><a href="https://www.tbank.ru/cf/1ZddEeAvzU1" target="_blank" rel="noopener">Поддержать проект</a></p>' + '</div></div></div>'; } function renderHelpModal(){ return '<div class="laiso-modal-bg" data-action="close-modal-bg"><div class="laiso-modal" data-stop>' + '<div class="laiso-row" style="justify-content:space-between;align-items:center;margin-bottom:8px;">' + '<h2 class="laiso-modal-title">Как пользоваться</h2><button class="laiso-back" data-action="close-modal">Закрыть</button></div>' + '<div class="laiso-stack" style="font-size:12px;line-height:1.6;">' + '<p><strong>1.</strong> «Добавить пластинку» → введи артиста и название → «→».</p>' + '<p><strong>2.</strong> Выбери своего кандидата из списка — подтянется треклист.</p>' + '<p><strong>3.</strong> Добавь до ' + SESSION_LIMIT + ' пластинок, нажми «Готово → треклисты».</p>' + '<p><strong>4.</strong> Проверь BPM/Key, собери сет.</p>' + '<p style="color:var(--text-tertiary);font-size:11px;">Если открыто как file://, часть API заблокируется CORS. Используй https-хост (Tilda) или локальный сервер.</p>' + '</div></div></div>'; } function renderConfirmClearModal(){ return '<div class="laiso-modal-bg" data-action="close-modal-bg"><div class="laiso-modal" data-stop>' + '<h2 class="laiso-modal-title">Точно стереть все данные?</h2>' + '<p>Удалит все пластинки, сеты и локальные настройки приложения. Действие необратимо.</p>' + '<div class="laiso-row" style="margin-top:16px;">' + '<button class="laiso-btn laiso-btn-secondary laiso-grow" data-action="close-modal">Отмена</button>' + '<button class="laiso-btn laiso-btn-warning laiso-grow" data-action="clear-data-confirm">Да, стереть всё</button>' + '</div>' + '</div></div>'; } function renderModal(){ if (state.modal === 'add-vinyl') return renderAddModal(); if (state.modal === 'manual-vinyl') return renderManualVinylModal(); if (state.modal === 'about') return renderAboutModal(); if (state.modal === 'help') return renderHelpModal(); if (state.modal === 'confirm-clear') return renderConfirmClearModal(); return ''; }

